def canCompleteCircuit(gas, cost):
    if sum(gas) < sum(cost):
        return -1

    start = 0
    total = 0
    for i in range(len(gas)):
        total += gas[i] - cost[i]
        if total < 0:
            # Reset fuel and candidate starting point
            total = 0
            start = i + 1

    return start

cppCode:
int canCompleteCircuit(vector<int>& gas, vector<int>& cost) {
    int sum_gas = 0, sum_cost = 0;
    for (int g : gas) sum_gas += g;
    for (int c : cost) sum_cost += c;
    if (sum_gas < sum_cost) return -1;

    int start = 0;
    int total = 0;
    for (int i = 0; i < gas.size(); ++i) {
        total += gas[i] - cost[i];
        if (total < 0) {
            total = 0;
            start = i + 1;
        }
    }
    return start;
}

