def partitionLabels(s):
    # Record last occurrence of each char
    last_idx = {char: i for i, char in enumerate(s)}

    res = []
    start = end = 0
    for i, char in enumerate(s):
        end = max(end, last_idx[char])
        if i == end:
            res.append(end - start + 1)
            start = i + 1
    return res

