def minPatches(nums, n):
    patches = 0
    miss = 1
    i = 0
    while miss <= n:
        if i < len(nums) and nums[i] <= miss:
            miss += nums[i]
            i += 1
        else:
            # Patch the missing number, doubling our reach
            miss += miss
            patches += 1
    return patches

cppCode:
int minPatches(vector<int>& nums, int n) {
    int patches = 0;
    long long miss = 1;
    int i = 0;
    while (miss <= n) {
        if (i < nums.size() && nums[i] <= miss) {
            miss += nums[i++];
        } else {
            miss += miss;
            patches++;
        }
    }
    return patches;
}
